#!/usr/bin/env tsx
/**
 * tools/checkModelAvailability.ts
 *
 * Checks whether 'openai/gpt-5.4' is available via the VideoDB proxy for both
 * use cases this project depends on, using THE EXACT SAME code paths as the app:
 *
 *   1. FEN extraction  (extractFenFromImage)
 *      — same message structure, same prompt, same math-validation + retry loop
 *        as src/main/services/llm.service.ts
 *      — uses the real chess indexing prompt from
 *        src/shared/config/game-coaching.ts
 *      — sends a minimal 1×1 PNG (the app sends a real screenshot; the model
 *        behaviour under the prompt is what we're testing)
 *
 *   2. Coaching text completion  (chatCompletion)
 *      — same client.chat.completions.create call as in chatCompletion()
 *      — uses the real CHESS_SYSTEM_PROMPT and liveAssistPrompt from the app
 *
 * Usage:
 *   npx tsx tools/checkModelAvailability.ts <apiKey> [apiUrl]
 *
 *   apiKey  — Your VideoDB API key
 *   apiUrl  — Optional base URL (default: https://api.videodb.io)
 *
 * Exit codes:
 *   0 — both checks passed
 *   1 — one or both checks failed
 *   2 — bad arguments / setup error
 */

import OpenAI from 'openai';
import { getGameIndexingPrompt, getGameLiveAssistPrompt } from '../src/shared/config/game-coaching';

// ─── Constants (mirrors src/main/services/llm.service.ts) ────────────────────

const MODEL          = 'openai/gpt-5.4';
const DEFAULT_API_URL = 'https://api.videodb.io';
const MAX_TOKENS_FEN  = 2048;   // same as extractFenFromImage
const MAX_TOKENS_CHAT = 4096;   // same as this.config.maxTokens default
const TEMPERATURE     = 0.7;    // same as this.config.temperature default
const MAX_RETRIES     = 2;      // same as extractFenFromImage maxRetries default

// ─── Real prompts from the app ────────────────────────────────────────────────

/** Exact prompt passed to extractFenFromImage() for chess */
const INDEXING_PROMPT = getGameIndexingPrompt('chess');

/**
 * Exact system prompt used in live-assist.service.ts for chess coaching.
 * Copied verbatim — kept here so the script has no Electron dependency.
 */
const CHESS_SYSTEM_PROMPT = `ROLE
You are a chess coach focused on the current board only.

SOURCE RESTRICTIONS
- Use only the provided current visual board/FEN context and chess engine output.
- Do not use transcript/audio.

STRICT RULES
- Return ONLY JSON with keys say_this and ask_this.
- say_this: exactly one clear paragraph explaining the best move and why it is best in this position.
- ask_this: exactly one short drill sentence.
- Prioritize concrete tactical/positional reasons (threats, king safety, piece activity, pawn structure, forcing lines).
- If engine details are present, use them directly.
- Do not output markdown.`;

/** Exact game-level prompt passed as the second system message */
const LIVE_ASSIST_PROMPT = getGameLiveAssistPrompt('chess');

/**
 * A minimal 1×1 white pixel PNG encoded as base64.
 * The app sends a real cropped screenshot; here we just need something valid
 * so the vision endpoint doesn't reject the message format.
 */
const MINIMAL_PNG_BASE64 =
 "";

// ─── Type mirrors from llm.service.ts ────────────────────────────────────────

type VisionMessage = {
  role: 'user' | 'assistant';
  content: string | Array<{ type: string; text?: string; image_url?: { url: string } }>;
};

// ─── Helpers ─────────────────────────────────────────────────────────────────

function pass(label: string, detail?: string) {
  const extra = detail ? `  →  ${detail}` : '';
  console.log(`  ✓  ${label}${extra}`);
}

function fail(label: string, detail?: string) {
  const extra = detail ? `  →  ${detail}` : '';
  console.error(`  ✗  ${label}${extra}`);
}

function section(title: string) {
  console.log(`\n${'─'.repeat(64)}`);
  console.log(`  ${title}`);
  console.log('─'.repeat(64));
}

// ─── Check 1: FEN extraction — mirrors extractFenFromImage() exactly ─────────

async function checkFenExtraction(client: OpenAI): Promise<boolean> {
  section('Check 1 — FEN extraction  (extractFenFromImage path)');
  console.log(`  Prompt : chess indexingPrompt from game-coaching.ts (${INDEXING_PROMPT.length} chars)`);
  console.log(`  Image  : minimal 1×1 PNG (real app sends cropped screenshot)`);
  console.log(`  Tokens : max_tokens=${MAX_TOKENS_FEN}, retries=${MAX_RETRIES}`);

  const dataUrl = `data:image/png;base64,${MINIMAL_PNG_BASE64}`;

  // Exact same messages array as in extractFenFromImage()
  const messages: VisionMessage[] = [
    {
      role: 'user',
      content: [
        { type: 'text', text: INDEXING_PROMPT },
        { type: 'image_url', image_url: { url: dataUrl } },
      ],
    },
  ];

  let savedPerspective: 'white' | 'black' = 'white';

  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      console.log(`\n  Attempt ${attempt + 1}/${MAX_RETRIES + 1} — calling ${MODEL}…`);

      // Exact same API call as extractFenFromImage()
      const response = await (client.chat.completions.create as (
        params: {
          model: string;
          messages: VisionMessage[];
          max_tokens: number;
          stream: false;
        }
      ) => Promise<OpenAI.Chat.ChatCompletion>)({
        model: MODEL,
        messages,
        max_tokens: MAX_TOKENS_FEN,
        stream: false,
      });

      const rawText = response.choices[0]?.message?.content?.trim() || '';
      const usage   = response.usage;

      console.log(`\n  finish_reason : ${response.choices[0]?.finish_reason ?? 'unknown'}`);
      console.log(`  tokens        : prompt=${usage?.prompt_tokens ?? '?'}, completion=${usage?.completion_tokens ?? '?'}`);
      console.log(`\n  Raw response (first 600 chars):\n${rawText.slice(0, 600).split('\n').map(l => `    ${l}`).join('\n')}`);

      // ── Exact logic from extractFenFromImage() ─────────────────────────────

      // Parse perspective tag
      const perspectiveMatch = rawText.match(/<perspective>\s*(.*?)\s*<\/perspective>/is);
      if (perspectiveMatch) {
        savedPerspective = perspectiveMatch[1].toLowerCase().includes('black') ? 'black' : 'white';
      } else {
        console.warn(`\n  ⚠  <perspective> tag missing — defaulting to white`);
      }

      // Parse raw_board tag
      const rawBoardMatches = [...rawText.matchAll(/<raw_board>\s*(.*?)\s*<\/raw_board>/gis)];
      if (!rawBoardMatches.length) {
        fail(`<raw_board> tag not found in response (attempt ${attempt + 1})`);
        if (attempt < MAX_RETRIES) {
          console.log('  Retrying…');
          continue;
        }
        return false;
      }

      const rawBoard = rawBoardMatches[rawBoardMatches.length - 1][1]
        .replace(/\s+/g, '').replace(/\n/g, '');

      // Validate math — exact same logic as extractFenFromImage()
      const ranks = rawBoard.split('/');
      let mathError: string | null = null;
      if (ranks.length !== 8) {
        mathError = `Board has ${ranks.length} ranks instead of 8.`;
      } else {
        for (let i = 0; i < ranks.length; i++) {
          let squares = 0;
          for (const ch of ranks[i]) {
            if (/\d/.test(ch)) squares += parseInt(ch, 10);
            else if (/[a-zA-Z]/.test(ch)) squares += 1;
            else { mathError = `Invalid character '${ch}' in rank ${i + 1}.`; break; }
          }
          if (mathError) break;
          if (squares !== 8) {
            mathError = `Visual Row ${i + 1} ('${ranks[i]}') sums to ${squares} instead of 8.`;
            break;
          }
        }
      }

      if (!mathError) {
        // transform_to_fen: reverse for black perspective — exact same as extractFenFromImage()
        let fenBoard = rawBoard;
        if (savedPerspective === 'black') {
          const rows = rawBoard.split('/');
          rows.reverse();
          fenBoard = rows.map(r => r.split('').reverse().join('')).join('/');
        }
        pass(
          'FEN extraction path is functional',
          `fenBoard=${fenBoard}  perspective=${savedPerspective}`
        );
        return true;
      }

      // Math error — same retry message as extractFenFromImage()
      console.warn(`\n  ⚠  Math error: ${mathError}`);
      if (attempt < MAX_RETRIES) {
        messages.push({ role: 'assistant', content: rawText });
        messages.push({ role: 'user', content: `Mathematical error: ${mathError} Please correct <raw_board>.` });
        console.log('  Retrying with math-correction message…');
      }

    } catch (err) {
      const msg    = err instanceof Error ? err.message : String(err);
      const status = (err as { status?: number }).status;
      fail(`API error on attempt ${attempt + 1} (HTTP ${status ?? 'N/A'})`, msg);
      return false;
    }
  }

  fail('FEN extraction failed after all attempts — model reachable but not producing valid output');
  return false;
}

// ─── Check 2: Coaching — mirrors chatCompletion() exactly ────────────────────

async function checkCoaching(client: OpenAI): Promise<boolean> {
  section('Check 2 — Coaching text completion  (chatCompletion path)');

  // Exact same message structure as processTranscriptInner() in live-assist.service.ts
  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: 'system', content: CHESS_SYSTEM_PROMPT },
    { role: 'system', content: LIVE_ASSIST_PROMPT },
    {
      role: 'user',
      content:
        '## CHESS POSITION CONTEXT\n' +
        'FEN: rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq e3 0 1\n' +
        'Engine summary: Best move e7e5. Eval: 0.10. Top lines: 1.e5 2.Nf3 Nc6\n\n' +
        '## TASK\nGenerate exactly one coaching tip for the CURRENT moment.',
    },
  ];

  console.log(`  System prompts : CHESS_SYSTEM_PROMPT + liveAssistPrompt from game-coaching.ts`);
  console.log(`  Tokens         : max_tokens=${MAX_TOKENS_CHAT}, temperature=${TEMPERATURE}`);
  console.log(`  Calling ${MODEL}…`);

  try {
    // Exact same API call as chatCompletion()
    const response = await client.chat.completions.create({
      model: MODEL,
      messages,
      max_tokens: MAX_TOKENS_CHAT,
      temperature: TEMPERATURE,
    });

    const content = response.choices[0]?.message?.content || '';
    const usage   = response.usage;

    console.log(`\n  finish_reason : ${response.choices[0]?.finish_reason ?? 'unknown'}`);
    console.log(`  tokens        : prompt=${usage?.prompt_tokens ?? '?'}, completion=${usage?.completion_tokens ?? '?'}`);
    console.log(`\n  Raw response (first 500 chars):\n${content.slice(0, 500).split('\n').map(l => `    ${l}`).join('\n')}`);

    if (!content) {
      fail('Empty response from model');
      return false;
    }

    // Try to parse JSON — exact same as chatCompletionJSON()
    const jsonStart = content.indexOf('{');
    const jsonEnd   = content.lastIndexOf('}');
    if (jsonStart !== -1 && jsonEnd > jsonStart) {
      try {
        const parsed = JSON.parse(content.slice(jsonStart, jsonEnd + 1)) as Record<string, unknown>;
        const hasSayThis = typeof parsed.say_this === 'string' && parsed.say_this.length > 0;
        const hasAskThis = typeof parsed.ask_this === 'string';

        if (hasSayThis) {
          pass(
            'Coaching path is functional — valid JSON with say_this',
            `say_this="${(parsed.say_this as string).slice(0, 80)}…"`
          );
          if (!hasAskThis) {
            console.warn('  ⚠  ask_this key missing (non-fatal)');
          }
          return true;
        }

        fail('JSON parsed but say_this key missing or empty', JSON.stringify(parsed).slice(0, 200));
        return false;
      } catch {
        // Not valid JSON — model responded but didn't follow the format
        console.warn('  ⚠  Response is not valid JSON — model may not be following the prompt format');
        fail('Could not parse JSON from response');
        return false;
      }
    }

    fail('Response contains no JSON object', content.slice(0, 200));
    return false;

  } catch (err) {
    const msg    = err instanceof Error ? err.message : String(err);
    const status = (err as { status?: number }).status;
    fail(`API error (HTTP ${status ?? 'N/A'})`, msg);
    return false;
  }
}

// ─── Main ─────────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const args = process.argv.slice(2);

  if (args.length < 1 || args[0] === '--help' || args[0] === '-h') {
    console.log('Usage: npx tsx tools/checkModelAvailability.ts <apiKey> [apiUrl]');
    console.log('');
    console.log('  apiKey   Your VideoDB API key');
    console.log(`  apiUrl   Optional base URL (default: ${DEFAULT_API_URL})`);
    console.log('');
    console.log('Checks that openai/gpt-5.4 is available via the VideoDB proxy using');
    console.log('the exact same code paths as the chess-lens app:');
    console.log('  1. FEN extraction  (extractFenFromImage — vision + math validation + retry)');
    console.log('  2. Coaching tips   (chatCompletion — system prompt + JSON output)');
    process.exit(args.length < 1 ? 2 : 0);
  }

  const [apiKey, apiUrl = DEFAULT_API_URL] = args;

  console.log('');
  console.log('╔════════════════════════════════════════════════════════════════╗');
  console.log('║       chess-lens — Model Availability Check                   ║');
  console.log('╚════════════════════════════════════════════════════════════════╝');
  console.log('');
  console.log(`  Model    : ${MODEL}`);
  console.log(`  Endpoint : ${apiUrl}`);
  console.log(`  API key  : ${apiKey.slice(0, 6)}${'*'.repeat(Math.max(0, apiKey.length - 6))}`);

  // Same client construction as LLMService constructor
  const client = new OpenAI({ apiKey, baseURL: apiUrl });

  // Run both checks — they share no state so can logically run in sequence
  // (run sequentially to keep console output readable)
  const fenOk      = await checkFenExtraction(client);
  const coachingOk = await checkCoaching(client);

  // ── Summary ────────────────────────────────────────────────────────────────
  section('Summary');

  const rows = [
    { label: 'FEN extraction  (extractFenFromImage)',  ok: fenOk },
    { label: 'Coaching tips   (chatCompletion)',        ok: coachingOk },
  ];

  for (const row of rows) {
    if (row.ok) pass(row.label); else fail(row.label);
  }

  console.log('');
  const allOk = fenOk && coachingOk;
  if (allOk) {
    console.log('  ✅  openai/gpt-5.4 is fully available — chess-lens will work correctly.');
  } else if (fenOk || coachingOk) {
    console.warn('  ⚠️   Partial availability — one check failed. See details above.');
  } else {
    console.error('  ❌  openai/gpt-5.4 is NOT available on this endpoint.');
    console.error('');
    console.error('  Possible fixes:');
    console.error('    • Verify your API key has access to openai/gpt-5.4');
    console.error('    • Check the apiUrl points to the correct VideoDB proxy');
    console.error('    • Contact VideoDB support to enable the model on your account');
  }

  console.log('');
  process.exit(allOk ? 0 : 1);
}

main().catch((err) => {
  console.error('\nUnhandled error:', err);
  process.exit(2);
});
